+    pub const fn dim() -> Self {
+        Self {
+            fg: None,
+            bg: None,
+            attributes: TextAttributes::DIM,
+            link_id: None,
+        }
+    }
+
+    /// Create an inverse (swapped fg/bg) style.
+    #[must_use]
